1	import http from "node:http";
2	import { readFile } from "node:fs/promises";
3	import { extname, join, resolve, normalize } from "node:path";
4	
5	const root = resolve(".");
6	const port = Number(process.env.PORT || 4177);
7	const host = process.env.HOST || "127.0.0.1";
8	
9	const types = {
10	  ".html": "text/html; charset=utf-8",
11	  ".css": "text/css; charset=utf-8",
12	  ".js": "text/javascript; charset=utf-8",
13	  ".json": "application/json; charset=utf-8",
14	  ".svg": "image/svg+xml"
15	};
16	
17	const server = http.createServer(async (req, res) => {
18	  try {
19	    const url = new URL(req.url || "/", `http://localhost:${port}`);
20	    const safePath = normalize(url.pathname === "/" ? "/index.html" : url.pathname).replace(/^(\.\.[/\\])+/, "");
21	    const filePath = join(root, safePath);
22	    const body = await readFile(filePath);
23	    res.writeHead(200, { "Content-Type": types[extname(filePath)] || "application/octet-stream" });
24	    res.end(body);
25	  } catch {
26	    res.writeHead(404, { "Content-Type": "text/plain; charset=utf-8" });
27	    res.end("Not found");
28	  }
29	});
30	
31	server.listen(port, host, () => {
32	  console.log(`Skill Resource Library running at http://${host}:${port}`);
33	});
